 52→function parseTenantAllowlist(raw: string): Map<string, Set<string>> {
 53→  const result = new Map<string, Set<string>>();
 54→  raw
 55→    .split(',')
 56→    .map((entry) => entry.trim())
 57→    .filter(Boolean)
 58→    .forEach((entry) => {
 59→      const [userId, tenantId] = entry.split(':').map((part) => part.trim());
 60→      if (!userId || !tenantId) return;
 61→      const existing = result.get(userId) || new Set<string>();
 62→      existing.add(tenantId);
 63→      result.set(userId, existing);
 64→    });
 65→  return result;
