249→          jsonrpc: '2.0',
250→          id,
251→          error: { code: -32601, message: `Method not found: ${method}` }
252→        });
253→    }
254→
255→    res.json({
256→      jsonrpc: '2.0',
257→      id,
258→      result
259→    });
260→  } catch (error: unknown) {
261→    const errorMessage = error instanceof Error ? error.message : 'Unknown error';
262→    console.error('MCP error:', error);
263→    res.json({
264→      jsonrpc: '2.0',
265→      id,
266→      error: { code: -32603, message: errorMessage }
267→    });
268→  }
