287→  // Send initial connected event
288→  res.write(`event: connected\ndata: {"status": "ok"}\n\n`);
289→
290→  // Keep connection alive
291→  const keepAlive = setInterval(() => {
292→    res.write(`event: ping\ndata: ${Date.now()}\n\n`);
