/**
 * We test the route handler logic directly by importing the router's handler
 * through the service layer rather than spinning up an HTTP server (no supertest
 * in devDeps). The download endpoint is a pure function of resolveDownloadToken,
 * which is already fully tested above. Here we verify the HTTP contract:
 * 404 for invalid token, correct headers+download call for valid token.
 */
describe('Router: GET /exports/download/:token', () => {
  // Import the router lazily so mocks are already installed
  let exportRouter: import('express').Router;

  beforeEach(async () => {
    vi.stubEnv('EXPORT_ALLOW_ANY_TENANT', 'true');
    vi.mocked(buildWorkbookFile).mockResolvedValue(undefined);
    // Dynamic import ensures the module uses the already-hoisted vi.mock stubs
    const mod = await import('../src/exports/router.js');
    exportRouter = mod.exportRouter;
  });

  afterEach(() => {
    vi.unstubAllEnvs();
  });

  it('responds 404 for an invalid download token', () => {
    const req = makeReq({ params: { token: 'completely-invalid-token' } });
    const res = makeRes();

    // Find and invoke the download route handler directly
    // Express Router stores layers; we invoke the last registered handler (index 2)
    const layers = (exportRouter as unknown as { stack: { route?: { path: string; stack: { handle: Function }[] } }[] }).stack;
    const downloadLayer = layers.find(
      (l) => l.route?.path === '/exports/download/:token'
    );
    expect(downloadLayer).toBeDefined();
    const handler = downloadLayer!.route!.stack[0].handle;
    handler(req, res, vi.fn());

    expect(res._status).toBe(404);
    expect((res._body as { error: string }).error).toMatch(/invalid|expired/i);
  });

  it('calls res.download with correct filePath and fileName for valid token', async () => {
    // Create a real job so resolveDownloadToken returns something
    const { job } = await createExcelExportJob(
      makeJobParams({ userId: 'user-router', tenantId: 'user-router' })
    );
    const token = job.downloadToken!;

    const req = makeReq({ params: { token } });
    const res = makeRes();

    const layers = (exportRouter as unknown as { stack: { route?: { path: string; stack: { handle: Function }[] } }[] }).stack;
    const downloadLayer = layers.find(
      (l) => l.route?.path === '/exports/download/:token'
    );
    const handler = downloadLayer!.route!.stack[0].handle;
    await handler(req, res, vi.fn());

    expect(res._downloadFile).toContain('.xlsx');
    expect(res._downloadName).toMatch(/\.xlsx$/);
    // Content-Type header should be set for xlsx
    expect(res.setHeader).toHaveBeenCalledWith(
      'Content-Type',
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    );
  });
});
