{"parentUuid":"2eb12ae0-92cd-44ab-8422-30f75cbd027b","isSidechain":true,"userType":"external","cwd":"/Users/AlexUA/claude/joyus-ai","sessionId":"faadca9e-fcad-4116-9f1e-f1241c7f85f7","version":"2.1.59","gitBranch":"codex/scaling-coding-research","agentId":"ac5fdffbf9b237ba6","slug":"streamed-jingling-beaver","type":"user","message":{"role":"user","content":[{"tool_use_id":"REDACTED","type":"tool_result","content":"     1→/**
     2→ * MCP Token Verification
     3→ * Verifies Bearer tokens for MCP requests
     4→ */
     5→
     6→import { eq, and } from 'drizzle-orm';
     7→
     8→import { db, users, connections, type Service } from '../db/client.js';
     9→
    10→interface UserWithConnections {
    11→  id: string;
    12→  email: string;
    13→  name: string | null;
    14→  connections: {
    15→    service: string;
    16→    accessToken: string;
    17→    refreshToken: string | null;
    18→    expiresAt: Date | null;
    19→    metadata: unknown;
    20→  }[];
    21→}
    22→
    23→/**
    24→ * Verify an MCP token and return the user if valid
    25→ */
    26→export async function verifyMcpToken(token: string): Promise<boolean> {
    27→  const [user] = await db
    28→    .select({ id: users.id })
    29→    .from(users)
    30→    .where(eq(users.mcpToken, token))
    31→    .limit(1);
    32→  return !!user;
    33→}
    34→
    35→/**
    36→ * Get user from MCP token with their connections
    37→ */
    38→export async function getUserFromToken(token: string): Promise<UserWithConnections | null> {
    39→  const [user] = await db
    40→    .select()
    41→    .from(users)
    42→    .where(eq(users.mcpToken, token))
    43→    .limit(1);
    44→
    45→  if (!user) return null;
    46→
    47→  const userConnections = await db
    48→    .select()
    49→    .from(connections)
    50→    .where(eq(connections.userId, user.id));
    51→
    52→  return {
    53→    id: user.id,
    54→    email: user.email,
    55→    name: user.name,
    56→    connections: userConnections.map((c) => ({
    57→      service: c.service,
    58→      accessToken: c.accessToken,
    59→      refreshToken: c.refreshToken,
    60→      expiresAt: c.expiresAt,
    61→      metadata: c.metadata
    62→    }))
    63→  };
    64→}
    65→
    66→/**
    67→ * Get a specific service connection for a user
    68→ */
    69→export async function getConnection(userId: string, service: string) {
    70→  const [connection] = await db
    71→    .select()
    72→    .from(connections)
    73→    .where(
    74→      and(
    75→        eq(connections.userId, userId),
    76→        eq(connections.service, service as Service)
    77→      )
    78→    )
    79→    .limit(1);
    80→  return connection || null;
    81→}
    82→
    83→/**
