   245→export async function createExcelExportJob(params: CreateExportJobParams): Promise<{ job: ExcelExportJob; downloadUrl: string }> {
   246→  assertTenantAccess(params.userId, params.tenantId);
   247→
   248→  const scope = normalizeExportScope(params.request.scope);
   249→  const locations = normalizeExportLocations(params.request.locations);
   250→  const now = nowIso();
   251→  const jobId = createId();
   252→  const fileName = `export-${params.tenantId}-${jobId}.xlsx`;
   253→  const outputDir = path.join(exportRootDir(), params.tenantId);
   254→  const outputPath = path.join(outputDir, fileName);
   255→
   256→  const initialJob: ExcelExportJob = {
   257→    id: jobId,
   258→    userId: params.userId,
   259→    tenantId: params.tenantId,
   260→    status: 'pending',
   261→    scope,
   262→    locations,
   263→    dateStart: params.request.date_start,
   264→    dateEnd: params.request.date_end,
   265→    scenarioId: params.request.scenario_id,
   266→    filePath: outputPath,
   267→    fileName,
   268→    createdAt: now,
   269→    updatedAt: now,
   270→  };
   271→  exportJobs.set(jobId, initialJob);
   272→
   273→  try {
   274→    await mkdir(outputDir, { recursive: true });
   275→    const workbook = isWorkbookPayload(params.request.workbook_data)
   276→      ? params.request.workbook_data
   277→      : defaultWorkbookPayload(params.tenantId, params.userId, scope, locations, params.request);
   278→
   279→    await buildWorkbookFile({
   280→      outputPath,
   281→      workbook,
   282→    });
   283→
   284→    const fileStats = await stat(outputPath);
   285→    const token = randomBytes(24).toString('hex');
   286→    const expiresAtMs = Date.now() + signedUrlTtlSeconds() * 1000;
   287→    const expiresAtIso = new Date(expiresAtMs).toISOString();
   288→    const downloadUrl = buildDownloadUrl(params.baseUrl, token);
   289→
   290→    downloadTokenToJob.set(token, { jobId, expiresAtMs });
   291→    exportJobs.set(jobId, {
   292→      ...initialJob,
   293→      status: 'completed',
   294→      fileSizeBytes: fileStats.size,
   295→      downloadToken: token,
   296→      downloadExpiresAt: expiresAtIso,
   297→      updatedAt: nowIso(),
   298→    });
   299→
   300→    const completedJob = exportJobs.get(jobId);
   301→    if (!completedJob) {
   302→      throw new Error('Export job was not persisted.');
   303→    }
   304→
   305→    return { job: completedJob, downloadUrl };
   306→  } catch (error) {
   307→    const message = error instanceof Error ? error.message : String(error);
   308→    exportJobs.set(jobId, {
   309→      ...initialJob,
   310→      status: 'failed',
   311→      error: message,
   312→      updatedAt: nowIso(),
   313→    });
   314→    throw error;
   315→  }
   316→}
